﻿"""Executable gate and workflow runners for closeout review."""

from __future__ import annotations

import os
import subprocess
from pathlib import Path

from ..workflow import run_first_cycle
from .models import CommandResult, CommandRunner, ScoreItem, WorkflowRunner


def _run_gate_commands(project_root: Path, runner: CommandRunner) -> dict[str, CommandResult]:
    commands = {
        "ruff": ("uv", "run", "ruff", "check"),
        "mypy": ("uv", "run", "mypy"),
        "pytest": (
            "uv",
            "run",
            "pytest",
            "--cov=slowbrain",
            "--cov-report=term-missing",
            "--cov-report=json:reports\\coverage.json",
        ),
    }
    return {name: runner(command, project_root) for name, command in commands.items()}


def _run_command(command: tuple[str, ...], cwd: Path) -> CommandResult:
    completed = subprocess.run(command, cwd=cwd, capture_output=True, text=True, check=False)
    return CommandResult(command, completed.returncode, completed.stdout, completed.stderr)


def _run_workflow(project_root: Path, workflow_runner: WorkflowRunner | None) -> dict[str, object]:
    previous_market_data_enabled = os.environ.get("SLOWBRAIN_MARKET_DATA_ENABLED")
    if workflow_runner is None:
        os.environ["SLOWBRAIN_MARKET_DATA_ENABLED"] = "false"
    try:
        payload = workflow_runner(project_root) if workflow_runner else run_first_cycle(project_root)
    except (FileNotFoundError, KeyError, TypeError, ValueError):
        return {}
    finally:
        if workflow_runner is None:
            if previous_market_data_enabled is None:
                os.environ.pop("SLOWBRAIN_MARKET_DATA_ENABLED", None)
            else:
                os.environ["SLOWBRAIN_MARKET_DATA_ENABLED"] = previous_market_data_enabled
    return payload if isinstance(payload, dict) else {}


def _criterion(criterion_id: str, category: str, passed: bool, evidence: str) -> ScoreItem:
    return ScoreItem(criterion_id, category, passed, 5 if passed else 0, evidence, f"{category}: {criterion_id}")

